VALUES
  ('social-worker-moex-06750', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「卑南溪是一條黑黑的長歌／風大雨苦撿柴的人呵／流水流來流木，下一步／試 探的赤足不慎便印證／生命只等於生活／我不知道柴火一斤多少錢／一株合抱的 枯樹可以燃燒多久／大水來了呵，許多人喊著／爭恐地涉水而過／遠遠的沙洲上， 木麻黃的防風林／早已流走。大水流來／一些流木，擱淺在沙洲上／如果試探的 赤足／不慎，便印證／生命只等於生活」閱讀上文可知，作者所要闡釋的意旨是：', '["和親人一起奮鬥，可以化解生活之苦", "人們破壞環境，大自然終將適時反撲", "甘冒風險的謀生模式，顯示生命的無奈與艱辛", "為了搶奪價值不菲的漂流木，人們不顧生命危險，競相在沙洲上你爭我奪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06751', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列各項民俗活動，何者不具有驅病祛邪的意義？', '["春節—請門神、掛桃符", "元宵—吃湯圓、提燈籠", "端午—插艾草、飲雄黃酒", "重陽—插茱萸、飲菊花酒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06752', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '李白〈春夜宴從弟桃花園序〉：「夫天地者，萬物之逆旅；光陰者，百代之過客， 而浮生若夢，為歡幾何？古人秉燭夜遊，良有以也。」以下何者較貼近上文文意？', '["天生我材必有用，請君為我傾耳聽", "鐘鼓饌玉不足貴，但願長醉不用醒", "古來聖賢皆寂寞，唯有飲者留其名", "人生得意須盡歡，莫使金樽空對月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06753', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《詩經‧衛風‧伯兮》：「自伯之東，首如飛蓬。豈無膏沐，誰適為容？」以下詩 詞所表現的情意與此最不相應的是：', '["自君之出矣，明鏡不復治。思君如流水，何有窮已時", "自君之出矣，蛾眉不復掃。寳鑑委埃塵，玉容為誰好", "小山重疊金明滅，鬢雲欲度香腮雪。懶起畫蛾眉，弄妝梳洗遲", "閨中少婦不知愁，春日凝妝上翠樓。忽見陌頭楊柳色，悔教夫婿覓封侯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06754', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '古代文人的作品裡，涉及愛情的詩篇甚多，下列四句都是哀婉悱惻的愛情悲歌，且 都與歷史事件有關。請問這四句的作者、題目和相關的歷史事件，何者正確？', '["「虞兮虞兮奈若何」：白居易〈長恨歌〉‧「安史之亂」", "「銅雀春深鎖二喬」：項羽〈垓下歌〉‧「烏江自刎」", "「驚破霓裳羽衣曲」：杜牧〈赤壁〉‧「赤壁之戰」", "「衝冠一怒為紅顏」：吳偉業〈圓圓曲〉‧「清兵入關」 請依下文回答第13題至第14題： 我來正逢秋雨節，陰氣晦昧無清風。潛心默禱若有應，豈非正直能感通。須臾靜掃眾峰 出，仰見突兀撐青空。紫蓋連延接天柱，石廩騰擲堆祝融。森然魄動下馬拜，松柏一徑 趨靈宮。粉牆丹柱動光彩，鬼物圖畫填青紅。升階傴僂薦脯酒，欲以菲薄明其衷。廟內 老人識神意，睢盱偵伺能鞠躬。手持盃珓導我擲，云此最吉餘難同。竄逐蠻荒幸不死，衣 食纔足甘長終。侯王將相望久絕，神縱欲福難為功"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06755', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '本詩的主旨，為作者：', '["藉遊山，盼得貴人相助", "因遊山，興起隱居的念頭", "藉遊山，題寫被貶的心情", "藉遊山，期許自己再創人生高峰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06756', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中「侯王將相望久絕，神縱欲福難為功」，意謂：', '["將相本無種，男兒當自強", "心如止水，不屑向嶽神祈求再成為王侯將相", "祈求嶽神能賜福給我，再創一番王侯將相的事業", "我早已斷絕王侯將相的希望，縱使嶽神要賜福給我也不可能了"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06757', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「古之人君有以千金求千里馬者，三年不能得。涓人言於君曰：『請求之。』君遣 之。三月得千里馬，馬已死，買其骨五百金，反以報君。君大怒曰：『所求者生馬， 安用死馬？捐五百金！』涓人對曰：『死馬且市之五百金，况生馬乎？天下必以王 為能市馬，馬今至矣！』於是不朞年，千里馬至者二。」下列選項何者較能說明涓 人的作為？', '["足智多謀", "浪費公帑", "虛與委蛇", "藉勢藉端"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06758', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「孫子荊年少時欲隱，語王武子曰『當枕石漱流』，誤曰『漱石枕流。』王曰：『流 非可枕，石非可漱。』孫曰：『所以枕流，欲洗其耳；所以漱石，欲礪其齒。』」如 果說孫子荊機智，最可能的理由是：', '["將錯就錯而為之解", "死皮賴臉而不認錯", "含渾其辭而無確解", "得理追擊而不饒人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06759', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「責善，朋友之道，然須忠告而善道之。悉其忠愛，致其婉曲，使彼聞之而可從， 繹之而可改，有所感而無所怒，乃為善耳！若先暴白其過惡，痛毀極詆，使無所容， 彼將發其愧恥憤恨之心；雖欲降以相從，而勢有所不能。」本文認為「責善」是否 能成功的因素在於下列何者？', '["指導和激勵", "態度和方法", "督促和反省", "知恥和發憤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
